package com.example.app.network.interceptor

import com.example.app.network.TokenProvider
import com.google.gson.Gson
import com.google.gson.annotations.SerializedName
import okhttp3.Authenticator
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import okhttp3.Response
import okhttp3.Route

class TokenRefreshAuthenticator(
    private val tokenProvider: TokenProvider,
    private val baseUrlProvider: () -> String
) : Authenticator {

    private val gson = Gson()

    data class RefreshTokenRequest(
        @SerializedName("refresh_token")
        val refreshToken: String
    )

    data class RefreshTokenResponse(
        @SerializedName("access_token")
        val accessToken: String,
        @SerializedName("refresh_token")
        val refreshToken: String
    )

    override fun authenticate(route: Route?, response: Response): Request? {
        // Prevent infinite loops
        if (response.request.header("X-Token-Refresh") != null) {
            tokenProvider.clearTokens()
            return null
        }

        val refreshToken = tokenProvider.getRefreshToken() ?: return null

        synchronized(this) {
            // Check if token was already refreshed by another thread
            val currentToken = tokenProvider.getAccessToken()
            val requestToken = response.request.header("Authorization")
                ?.removePrefix("Bearer ")

            if (currentToken != null && currentToken != requestToken) {
                return response.request.newBuilder()
                    .header("Authorization", "Bearer $currentToken")
                    .build()
            }

            // Attempt token refresh
            val newToken = refreshAccessToken(refreshToken)
            return if (newToken != null) {
                tokenProvider.saveAccessToken(newToken.accessToken)
                tokenProvider.saveRefreshToken(newToken.refreshToken)

                response.request.newBuilder()
                    .header("Authorization", "Bearer ${newToken.accessToken}")
                    .build()
            } else {
                tokenProvider.clearTokens()
                null
            }
        }
    }

    private fun refreshAccessToken(refreshToken: String): RefreshTokenResponse? {
        return try {
            val client = OkHttpClient.Builder().build()
            val body = gson.toJson(RefreshTokenRequest(refreshToken))
                .toRequestBody("application/json".toMediaType())

            val request = Request.Builder()
                .url("${baseUrlProvider()}auth/refresh")
                .post(body)
                .header("X-Token-Refresh", "true")
                .build()

            val response = client.newCall(request).execute()
            if (response.isSuccessful) {
                response.body?.string()?.let {
                    gson.fromJson(it, RefreshTokenResponse::class.java)
                }
            } else {
                null
            }
        } catch (e: Exception) {
            null
        }
    }
}

