package com.example.app.network

import com.example.app.network.api.UserApiService
import com.example.app.network.interceptor.AuthInterceptor
import com.example.app.network.interceptor.TokenRefreshAuthenticator
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var retrofit: Retrofit? = null
    private var tokenProvider: TokenProvider? = null

    private const val CONNECT_TIMEOUT = 30L
    private const val READ_TIMEOUT = 30L
    private const val WRITE_TIMEOUT = 30L

    fun initialize(tokenProvider: TokenProvider) {
        this.tokenProvider = tokenProvider
        this.retrofit = null // Reset to force rebuild
    }

    fun setEnvironment(environment: Environment) {
        Environment.current = environment
        this.retrofit = null // Reset to force rebuild with new base URL
    }

    private fun buildOkHttpClient(): OkHttpClient {
        val provider = tokenProvider
            ?: throw IllegalStateException("NetworkModule not initialized. Call initialize() first.")

        val builder = OkHttpClient.Builder()
            .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
            .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
            .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(provider))
            .authenticator(
                TokenRefreshAuthenticator(
                    tokenProvider = provider,
                    baseUrlProvider = { Environment.current.baseUrl }
                )
            )

        // Add logging for non-production environments
        if (Environment.current != Environment.PRODUCTION) {
            val loggingInterceptor = HttpLoggingInterceptor().apply {
                level = when (Environment.current) {
                    Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                    Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                    else -> HttpLoggingInterceptor.Level.NONE
                }
            }
            builder.addInterceptor(loggingInterceptor)
        }

        return builder.build()
    }

    private fun getRetrofit(): Retrofit {
        return retrofit ?: synchronized(this) {
            retrofit ?: buildRetrofit().also { retrofit = it }
        }
    }

    private fun buildRetrofit(): Retrofit {
        val gson = GsonBuilder()
            .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
            .setLenient()
            .create()

        return Retrofit.Builder()
            .baseUrl(Environment.current.baseUrl)
            .client(buildOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()
    }

    val userApiService: UserApiService
        get() = getRetrofit().create(UserApiService::class.java)
}

