package com.example.app.network

import retrofit2.Response
import java.io.IOException

suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): NetworkResult<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body != null) {
                NetworkResult.Success(body)
            } else {
                NetworkResult.Error(
                    code = response.code(),
                    message = "Response body is null"
                )
            }
        } else {
            val errorBody = response.errorBody()?.string()
            NetworkResult.Error(
                code = response.code(),
                message = errorBody ?: "Unknown error occurred (HTTP ${response.code()})"
            )
        }
    } catch (e: IOException) {
        NetworkResult.Error(
            message = "Network error: ${e.localizedMessage ?: "Please check your connection"}",
            exception = e
        )
    } catch (e: Exception) {
        NetworkResult.Error(
            message = "Unexpected error: ${e.localizedMessage ?: "Unknown error"}",
            exception = e
        )
    }
}

