        return safeApiCall { apiService.getCurrentUser() }
    }

    suspend fun updateUser(userId: Long, updates: Map<String, Any>): NetworkResult<ApiResponse<UserProfile>> {
        return safeApiCall { apiService.updateUser(userId, updates) }
    }

    suspend fun deleteUser(userId: Long): NetworkResult<ApiResponse<Unit>> {
        return safeApiCall { apiService.deleteUser(userId) }
    }

    suspend fun searchUsers(query: String, page: Int = 1, perPage: Int = 20): NetworkResult<PaginatedResponse<UserProfile>> {
        return safeApiCall { apiService.searchUsers(query, page, perPage) }
