class MainApplication : Application() {

    override fun onCreate() {
        super.onCreate()

        // Initialize network module
        val tokenProvider = SharedPrefsTokenProvider(this)
        NetworkModule.initialize(tokenProvider)

        // Set environment based on build config or flavor
        val environment = when (BuildConfig.BUILD_TYPE) {
            "debug" -> Environment.DEV
            "staging" -> Environment.STAGING
            "release" -> Environment.PRODUCTION
            else -> Environment.DEV
        }
        NetworkModule.setEnvironment(environment)
    }
