package com.example.app.ui

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.app.network.NetworkResult
import com.example.app.network.model.UserProfile
import com.example.app.network.repository.UserRepository
import kotlinx.coroutines.launch

class UserViewModel : ViewModel() {

    private val userRepository = UserRepository()

    private val _users = MutableLiveData<NetworkResult<List<UserProfile>>>()
    val users: LiveData<NetworkResult<List<UserProfile>>> = _users

    private val _currentUser = MutableLiveData<NetworkResult<UserProfile>>()
    val currentUser: LiveData<NetworkResult<UserProfile>> = _currentUser

    private val _userDetail = MutableLiveData<NetworkResult<UserProfile>>()
    val userDetail: LiveData<NetworkResult<UserProfile>> = _userDetail

    fun fetchUsers(page: Int = 1) {
        _users.value = NetworkResult.Loading
        viewModelScope.launch {
            val result = userRepository.getUsers(page)
            _users.value = result.map { it.data }
        }
    }

    fun fetchCurrentUser() {
        _currentUser.value = NetworkResult.Loading
        viewModelScope.launch {
            val result = userRepository.getCurrentUser()
            _currentUser.value = when (result) {
                is NetworkResult.Success -> {
                    val user = result.data.data
                    if (user != null) {
                        NetworkResult.Success(user)
                    } else {
                        NetworkResult.Error(message = "User data is null")
                    }
                }
                is NetworkResult.Error -> result
                is NetworkResult.Loading -> NetworkResult.Loading
            }
        }
    }

    fun fetchUserById(userId: Long) {
        _userDetail.value = NetworkResult.Loading
        viewModelScope.launch {
            val result = userRepository.getUserById(userId)
            _userDetail.value = when (result) {
                is NetworkResult.Success -> {
                    val user = result.data.data
                    if (user != null) {
                        NetworkResult.Success(user)
                    } else {
                        NetworkResult.Error(message = "User not found")
                    }
                }
                is NetworkResult.Error -> result
                is NetworkResult.Loading -> NetworkResult.Loading
            }
        }
    }

    fun updateUser(userId: Long, firstName: String?, lastName: String?) {
        viewModelScope.launch {
            val updates = mutableMapOf<String, Any>()
            firstName?.let { updates["first_name"] = it }
            lastName?.let { updates["last_name"] = it }

            val result = userRepository.updateUser(userId, updates)
            _userDetail.value = when (result) {
                is NetworkResult.Success -> {
                    val user = result.data.data
                    if (user != null) {
                        NetworkResult.Success(user)
                    } else {
                        NetworkResult.Error(message = "Update failed")
                    }
                }
                is NetworkResult.Error -> result
                is NetworkResult.Loading -> NetworkResult.Loading
            }
        }
    }

    fun searchUsers(query: String) {
        _users.value = NetworkResult.Loading
        viewModelScope.launch {
            val result = userRepository.searchUsers(query)
            _users.value = result.map { it.data }
        }
    }
}